<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Sorting Visualizer</title>
    <style>
        *,
        *::before,
        *::after {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        body {
            background: #1a1a2e;
            color: #e0e0e0;
            font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            min-height: 100vh;
            padding: 24px 16px;
            user-select: none;
        }

        h1 {
            font-size: 1.6rem;
            font-weight: 600;
            letter-spacing: 0.5px;
            margin-bottom: 20px;
            color: #c0c0d0;
            text-transform: uppercase;
            letter-spacing: 2px;
            font-size: 1.1rem;
        }

        #bars {
            display: flex;
            align-items: flex-end;
            justify-content: center;
            gap: 2px;
            height: 420px;
            width: 100%;
            max-width: 900px;
            background: #16213e;
            border-radius: 12px;
            padding: 12px 10px;
            border: 1px solid #2a2a4a;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
            overflow: hidden;
        }

        .bar {
            flex: 1;
            min-width: 2px;
            background: linear-gradient(180deg, #5bc0eb 0%, #3a86ff 100%);
            border-radius: 4px 4px 0 0;
            transition: height 0.08s ease-out, background 0.15s ease, box-shadow 0.15s ease;
            position: relative;
        }

        .bar.comparing {
            background: linear-gradient(180deg, #f72585 0%, #b5179e 100%);
            box-shadow: 0 0 12px rgba(247, 37, 133, 0.6), 0 0 24px rgba(247, 37, 133, 0.25);
            z-index: 2;
        }

        .bar.sorted-portion {
            background: linear-gradient(180deg, #06d6a0 0%, #059669 100%);
            box-shadow: 0 0 6px rgba(6, 214, 160, 0.3);
        }

        .controls {
            display: flex;
            gap: 12px;
            margin-top: 20px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            background: #0f3460;
            color: #e0e0e0;
            border: 1px solid #2a2a4a;
            padding: 11px 22px;
            border-radius: 8px;
            cursor: pointer;
            font-size: 14px;
            font-weight: 500;
            letter-spacing: 0.4px;
            transition: background 0.2s, transform 0.12s, border-color 0.2s, box-shadow 0.2s;
            outline: none;
            white-space: nowrap;
        }

        button:hover {
            background: #1a5276;
            border-color: #4a6a9a;
            transform: translateY(-2px);
            box-shadow: 0 4px 14px rgba(0, 0, 0, 0.3);
        }

        button:active {
            transform: translateY(0);
            box-shadow: 0 2px 6px rgba(0, 0, 0, 0.3);
            transition: transform 0.05s, box-shadow 0.05s;
        }

        button:disabled {
            opacity: 0.5;
            cursor: not-allowed;
            transform: none;
            box-shadow: none;
        }

        #sort {
            background: #1a3a5c;
            border-color: #3a7abd;
            font-weight: 600;
        }

        #sort:hover {
            background: #1e4d7a;
            border-color: #5a9adf;
        }

        .status {
            margin-top: 14px;
            font-size: 13px;
            color: #8899aa;
            letter-spacing: 0.3px;
            min-height: 20px;
            text-align: center;
        }

        @media (max-width: 600px) {
            #bars {
                height: 280px;
                padding: 8px 6px;
                gap: 1px;
            }
            .bar {
                border-radius: 2px 2px 0 0;
            }
            button {
                padding: 9px 14px;
                font-size: 12px;
            }
            h1 {
                font-size: 0.9rem;
                margin-bottom: 12px;
            }
        }
    </style>
</head>
<body>
    <h1>Sorting Visualizer &mdash; Bubble Sort</h1>
    <div id="bars"></div>
    <div class="controls">
        <button id="sort">▶ Sort</button>
        <button id="shuffle">🔀 Shuffle</button>
        <button id="reset">↺ Reset</button>
    </div>
    <div class="status" id="status"></div>

    <script>
        (function() {
            // ─────────────────────────────────────
            // State
            // ─────────────────────────────────────
            const DEFAULT_SIZE = 25;
            let array = [];
            let defaultArray = [];
            let sortPass = 0; // which bubble-sort pass we're on (0-indexed)
            let sortIdx = 0; // current comparison index within the pass
            let lastCompared = []; // indices of bars being compared (for highlighting)
            let animationInterval = null;
            let isAnimating = false;

            // ─────────────────────────────────────
            // DOM references
            // ─────────────────────────────────────
            const barsContainer = document.getElementById('bars');
            const statusEl = document.getElementById('status');
            const sortBtn = document.getElementById('sort');
            const shuffleBtn = document.getElementById('shuffle');
            const resetBtn = document.getElementById('reset');

            // ─────────────────────────────────────
            // Utility: Fisher-Yates shuffle
            // ─────────────────────────────────────
            function shuffleArray(arr) {
                const a = [...arr];
                for (let i = a.length - 1; i > 0; i--) {
                    const j = Math.floor(Math.random() * (i + 1));
                    [a[i], a[j]] = [a[j], a[i]];
                }
                return a;
            }

            // ─────────────────────────────────────
            // Create initial array
            // ─────────────────────────────────────
            function createDefaultArray() {
                const arr = [];
                for (let i = 1; i <= DEFAULT_SIZE; i++) {
                    arr.push(i);
                }
                return shuffleArray(arr);
            }

            // ─────────────────────────────────────
            // Rendering
            // ─────────────────────────────────────
            function renderBars() {
                const existingBars = barsContainer.querySelectorAll('.bar');
                const n = array.length;

                // Determine value range for scaling
                const minVal = Math.min(...array, 0);
                const maxVal = Math.max(...array, 1);
                const range = maxVal - minVal || 1;

                // If the number of bars doesn't match, rebuild entirely
                if (existingBars.length !== n) {
                    barsContainer.innerHTML = '';
                    for (let i = 0; i < n; i++) {
                        const bar = document.createElement('div');
                        bar.className = 'bar';
                        const heightPct = ((array[i] - minVal) / range) * 100;
                        bar.style.height = heightPct + '%';
                        barsContainer.appendChild(bar);
                    }
                } else {
                    // Update existing bars in place (preserves transition)
                    for (let i = 0; i < n; i++) {
                        const bar = existingBars[i];
                        const heightPct = ((array[i] - minVal) / range) * 100;
                        bar.style.height = heightPct + '%';

                        // Reset classes
                        bar.className = 'bar';

                        // Highlight comparing pair
                        if (lastCompared.includes(i)) {
                            bar.classList.add('comparing');
                        }

                        // Mark sorted portion (rightmost elements after each pass)
                        // In bubble sort, after pass p, the rightmost (p+1) elements are in place
                        const sortedFromIndex = n - sortPass;
                        if (i >= sortedFromIndex && sortPass > 0 && !lastCompared.includes(i)) {
                            bar.classList.add('sorted-portion');
                        }
                    }
                }
            }

            // ─────────────────────────────────────
            // Core sorting logic
            // ─────────────────────────────────────
            function isSorted() {
                for (let i = 0; i < array.length - 1; i++) {
                    if (array[i] > array[i + 1]) return false;
                }
                return true;
            }

            function sortStep() {
                // Clear previous comparison highlight
                lastCompared = [];

                // If already sorted, we're done
                if (isSorted()) {
                    sortPass = 0;
                    sortIdx = 0;
                    return true;
                }

                const n = array.length;

                // If all passes complete
                if (sortPass >= n - 1) {
                    return true;
                }

                // Advance to next pass if current pass is exhausted
                while (sortPass < n - 1 && sortIdx > n - 2 - sortPass) {
                    sortPass++;
                    sortIdx = 0;
                }

                // Check again after advancing
                if (sortPass >= n - 1) {
                    return true;
                }

                // Perform exactly one comparison
                lastCompared = [sortIdx, sortIdx + 1];

                if (array[sortIdx] > array[sortIdx + 1]) {
                    // Swap
                    [array[sortIdx], array[sortIdx + 1]] = [array[sortIdx + 1], array[sortIdx]];
                }

                sortIdx++;

                const done = isSorted();
                if (done) {
                    lastCompared = [];
                    sortPass = 0;
                    sortIdx = 0;
                }

                return done;
            }

            // ─────────────────────────────────────
            // Animation control
            // ─────────────────────────────────────
            function stopAnimation() {
                if (animationInterval !== null) {
                    clearInterval(animationInterval);
                    animationInterval = null;
                }
                isAnimating = false;
                sortBtn.disabled = false;
                updateStatus();
            }

            function startAnimation() {
                if (isAnimating) return; // already running
                if (isSorted()) {
                    updateStatus();
                    return;
                }
                isAnimating = true;
                sortBtn.disabled = true;
                updateStatus();

                animationInterval = setInterval(() => {
                    const done = sortStep();
                    renderBars();
                    updateStatus();

                    if (done) {
                        stopAnimation();
                        lastCompared = [];
                        renderBars();
                        updateStatus();
                    }
                }, 30);
            }

            function updateStatus() {
                if (isSorted()) {
                    statusEl.textContent = '✓ Array is sorted';
                    statusEl.style.color = '#06d6a0';
                } else if (isAnimating) {
                    statusEl.textContent = '⟳ Sorting in progress…';
                    statusEl.style.color = '#f72585';
                } else {
                    statusEl.textContent = 'Ready — click Sort to begin';
                    statusEl.style.color = '#8899aa';
                }
            }

            // ─────────────────────────────────────
            // Public API (exposed on window.viz)
            // ─────────────────────────────────────
            function apiArray() {
                return [...array];
            }

            function apiSetArray(a) {
                stopAnimation();
                array = [...a];
                sortPass = 0;
                sortIdx = 0;
                lastCompared = [];
                renderBars();
                updateStatus();
            }

            function apiSortStep() {
                const done = sortStep();
                renderBars();
                updateStatus();
                return done;
            }

            function apiSorted() {
                return isSorted();
            }

            // Expose the API
            window.viz = {
                array: apiArray,
                setArray: apiSetArray,
                sortStep: apiSortStep,
                sorted: apiSorted,
            };

            // ─────────────────────────────────────
            // Button handlers
            // ─────────────────────────────────────
            sortBtn.addEventListener('click', () => {
                if (isSorted()) {
                    // Already sorted — nothing to animate
                    updateStatus();
                    return;
                }
                if (!isAnimating) {
                    startAnimation();
                }
            });

            shuffleBtn.addEventListener('click', () => {
                stopAnimation();
                array = shuffleArray(array);
                sortPass = 0;
                sortIdx = 0;
                lastCompared = [];
                renderBars();
                updateStatus();
            });

            resetBtn.addEventListener('click', () => {
                stopAnimation();
                array = [...defaultArray];
                sortPass = 0;
                sortIdx = 0;
                lastCompared = [];
                renderBars();
                updateStatus();
            });

            // ─────────────────────────────────────
            // Initialization
            // ─────────────────────────────────────
            function init() {
                defaultArray = createDefaultArray();
                array = [...defaultArray];
                sortPass = 0;
                sortIdx = 0;
                lastCompared = [];
                renderBars();
                updateStatus();
            }

            init();
        })();
    </script>
</body>
</html>
